def most_common_word(s):
    words = set(s.lower().split())
    count = {word: s.lower().count(word) for word in words}
    max_count, max_word = max((value, key) for key, value in count.items())
    if max_count > 1 and any(char.isalnum() for char in max_word):
        # Edge case: if the most common word has numbers or special characters, it may not be a real English word
        max_word = ''.join([char for char in max_word if char.isalpha()]).strip()
    return max_word
